If `item.leaves` is an empty array, we can handle it by checking if it has any elements before mapping over it. Here is the modified code to handle the case when `item.leaves` is an empty array:

```javascript
const output = data.map(item => {
    if (item.leaves.length === 0) {
        return {
            name: item.email_address.split('@')[0], // Extracting name from email address
            appointments: []
        };
    } else {
        return {
            name: item.leaves[0].employee_id,
            appointments: item.leaves.filter(leave => leave.approval_status !== "CANCELLED").map(leave => ({
                start: new Date(leave.start_date),
                end: new Date(leave.end_date),
                title: leave.leave_type,
                type: leave.leave_type,
                tentative: leave.approval_status === "PENDING" ? true : false
            }))
        };
    }
});

console.log(output);
```

